&lt;p&gt;&lt;span style=&quot;text-decoration: underline;&quot;&gt;&lt;strong&gt;&lt;span data-contrast=&quot;none&quot;&gt;Key Responsibilities&lt;/span&gt;&lt;/strong&gt;&lt;span data-ccp-props=&quot;{&amp;quot;335559738&amp;quot;:280,&amp;quot;335559739&amp;quot;:100,&amp;quot;335572079&amp;quot;:4,&amp;quot;335572080&amp;quot;:4,&amp;quot;335572081&amp;quot;:7949855,&amp;quot;469789806&amp;quot;:&amp;quot;single&amp;quot;}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
